  ('disabled-64311456-moex-00051', 'disabled-64311456', 'disabled-64311456-moex-114-146a7303', 'sub-disabled-64311456-02', NULL, 'single_choice', '關於社區工作的能力／資產觀點的敘述，下列何者錯誤？', '["社區發展應該採取由下而上，由內而外之路徑", "社區討論議題時，同時存在支持與反對者，這些人都是社區重要資產", "社區應首重內部成員的關係，而非與專家、贊助者、政治人物之關係", "協助引進外部專家，解決社區問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "437753a6f542", "answer_pdf_sha1": "5aec302d6f62", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00052', 'disabled-64311456', 'disabled-64311456-moex-114-146a7303', 'sub-disabled-64311456-02', NULL, 'single_choice', '關於國內團體工作發展的敘述，下列何者正確？', '["最早在大學設置相關課程的，是民國 60 年由東海大學社會系所開設的選 修課程", "臺灣最早以夏令營或露營的團體方式提供育樂或休閒是基督教兒童福利 基金會", "民國 89 年衛生福利部（原行政院衛生署）頒訂醫院評鑑標準，開始明訂 團體工作是社會工作者的工作項目之一", "社會工作師法明訂社會工作師的執行業務，包含團體之預防性與支持性服務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "437753a6f542", "answer_pdf_sha1": "5aec302d6f62", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00053', 'disabled-64311456', 'disabled-64311456-moex-114-146a7303', 'sub-disabled-64311456-02', NULL, 'single_choice', '關於社會團體工作的團體結構，下列敘述何者正確？①依據團體的目的決定', '["情緒障礙和社會適應不良的兒童營隊，理想人數大約是 7 到 9 人", "應敏銳了解同性或異性團體對成員可能產生的影響", "剛形成團體時就 要選出領導者，如此才能培養領導能力", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "437753a6f542", "answer_pdf_sha1": "5aec302d6f62", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
